Create PROC [CREATE_HSN] @FromDate datetime, @ToDate datetime AS IF OBJECT_ID('HSN','U') IS NOT NULL DROP TABLE HSN IF OBJECT_ID('HSN_Info','U') IS NOT NULL DROP TABLE HSN_Info IF OBJECT_ID('tempdb..##HSNCODETABLE') IS NOT NULL EXEC ('DROP TABLE ##HSNCODETABLE') DECLARE @HSNCodeField AS CHAR(12) DECLARE @IMTableQry AS VARCHAR(500) SELECT @HSNCodeField=Txt FROM SysParam WHERE ParamCode='AnalysisCodeUsedToStoreHSNCode' SET @IMTableQry= 'SELECT StockNo,'+ @HSNCodeField +' AS HSNCODE INTO ##HSNCODETABLE FROM ItemMaster' EXEC (@IMTableQry) SELECT [HSN], [Description],[UQC] ,CAST(SUM(ISNULL([Total Quantity],0)) AS DECimal(10,2)) AS [Total Quantity], CAST(SUM(ISNULL([Total Value],0))AS DECimal(10,2)) AS [Total Value],CAST(SUM(ISNULL([Taxable Value],0)) AS DECimal(10,2)) AS [Taxable Value],CAST(SUM(ISNULL([Integrated Tax Amount],0)) AS DECimal(10,2)) AS [Integrated Tax Amount],CAST(SUM(ISNULL([Central Tax Amount],0)) AS DECimal(10,2)) AS [Central Tax Amount], CAST(SUM(ISNULL([State/UT Tax Amount],0)) AS DECimal(10,2)) AS [State/UT Tax Amount],CAST(SUM(ISNULL([Cess Amount],0)) AS DECimal(10,2)) AS [Cess Amount] INTO HSN FROM (SELECT HSN.HSNCODE AS [HSN],'' AS [Description],   'UNT-UNITS' AS [UQC],SUM(ISNULL(STD.DocQty,0)) AS [Total Quantity],SUM(STD.DocEntNetValue-STD.DocEntTax) AS [Total Value],SUM(ISNULL(STD.TaxAV1,0)) AS [Taxable Value],SUM(CASE WHEN ISNULL(CS.SrcTaxType,0) IN (1) THEN ISNULL(STD.Taxcomp1,0) Else 0 END ) AS [Integrated Tax Amount],SUM(CASE WHEN ISNULL(CS.SrcTaxType,0) IN (0,99) THEN ISNULL(STD.Taxcomp1,0) Else 0 END ) AS [Central Tax Amount],SUM(CASE WHEN ISNULL(CS.SrcTaxType,0) IN (0,99) THEN ISNULL(STD.Taxcomp2,0) Else 0 END ) AS [State/UT Tax Amount],SUM(CASE WHEN ISNULL(CS.SrcTaxType,0) IN (1) THEN ISNULL(STD.Taxcomp2,0) Else ISNULL(STD.Taxcomp3,0) END ) AS [Cess Amount] FROM StkTrnDtls STD Inner Join ##HSNCODETABLE HSN ON HSN.StockNo=STD.StockNo Inner JOIN StkTrnHdr STH ON STD.TrnType=STH.TrnType AND STD.TrnCtrlNo=STH.TrnCtrlNo Inner JOIn ChainStores CS ON CS.Code=STH.PartyId WHERE STD.TrnType =2200 AND STD.Docdt>=@FromDate AND STD.Docdt<=@ToDate AND STD.DocEntVoidInd =0 GROUP BY HSN.HSNCODE UNION ALL SELECT HSN.HSNCODE AS [HSN], '' AS [Description], 'UNT-UNITS' AS [UQC], SUM(ISNULL(STD.DocQty,0)) AS [Total Quantity], SUM(ISNULL(STD.DocEntNetValue,0)) AS [Total Value], SUM(ISNULL(STD.TaxAV1,0)) AS [Taxable Value], SUM(CASE WHEN STD.CustTaxType='1' THEN ISNULL(STD.Taxcomp1,0) Else 0 END ) AS [Integrated Tax Amount], SUM(CASE WHEN STD.CustTaxType<>'1' THEN ISNULL(STD.Taxcomp1,0) Else 0 END ) AS [Central Tax Amount], SUM(CASE WHEN STD.CustTaxType<>'1' THEN ISNULL(STD.Taxcomp2,0) Else 0 END ) AS [State/UT Tax Amount], SUM(CASE WHEN STD.CustTaxType='1' THEN ISNULL(STD.Taxcomp2,0) Else ISNULL(STD.Taxcomp3,0) END ) AS [Cess Amount] FROM StkTrnDtls STD Inner Join ##HSNCODETABLE HSN  ON HSN.StockNo=STD.StockNo Inner JOIN StkTrnHdr STH ON STD.TrnType=STH.TrnType AND STD.TrnCtrlNo=STH.TrnCtrlNo WHERE STD.TrnType =2100 AND STD.Docdt>=@FromDate AND STD.Docdt<=@ToDate AND STD.DocEntVoidInd =0 GROUP BY HSN.HSNCODE UNION ALL SELECT HSN.HSNCODE AS [HSN], '' AS [Description],  'UNT-UNITS' AS [UQC], SUM(ISNULL(STD.DocQty,0)) * -1 AS [Total Quantity], SUM(ISNULL(STD.DocEntNetValue,0)) * -1 AS [Total Value], SUM(ISNULL(STD.TaxAV1,0)) * - 1 AS [Taxable Value], SUM(CASE WHEN STD.CustTaxType='1' THEN ISNULL(STD.Taxcomp1,0) Else 0 END ) AS [Integrated Tax Amount], SUM(CASE WHEN STD.CustTaxType<>'1' THEN ISNULL(STD.Taxcomp1,0) Else 0 END ) AS [Central Tax Amount], SUM(CASE WHEN STD.CustTaxType<>'1' THEN ISNULL(STD.Taxcomp2,0) Else 0 END ) AS [State/UT Tax Amount], SUM(CASE WHEN STD.CustTaxType='1' THEN ISNULL(STD.Taxcomp2,0) Else ISNULL(STD.Taxcomp3,0) END ) AS [Cess Amount] FROM StkTrnDtls STD Inner Join ##HSNCODETABLE HSN ON HSN.StockNo=STD.StockNo Inner JOIN StkTrnHdr STH ON STD.TrnType=STH.TrnType AND STD.TrnCtrlNo=STH.TrnCtrlNo WHERE STD.TrnType =1300 AND STD.Docdt>=@FromDate AND STD.Docdt<=@ToDate AND STD.DocEntVoidInd =0 GROUP BY HSN.HSNCODE  ) Temp1 GROUP BY [HSN], [Description], [UQC] SELECT  COUNT(*) [No. of HSN], SUM([Total Value]) AS [Total Value], SUM([Taxable Value]) AS [Total Taxable Value], SUM([Integrated Tax Amount]) AS [Total Integrated Tax], SUM([Central Tax Amount]) AS [Total Central Tax], SUM([State/UT Tax Amount]) AS [Total State/UT Tax], SUM([Cess Amount]) AS [Total Cess]  INTO HSN_Info FROM HSN IF OBJECT_ID('HSN_Header','U') IS NULL CREATE TABLE HSN_Header ([Summary For HSN(12)] Char(1) ) INSERT INTO InfoTable Values('HSN',2,'<<Default>>','HSN',10) 